#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int x, n, d;
        scanf("%d %d %d", &x, &n, &d);
        int h[n], a[d];
        for (int i = 0; i < n; i++) {
            scanf("%d", &h[i]);
        }
        for (int i = 0; i < d; i++) {
            scanf("%d", &a[i]);
        }
        int day = 0;
        while (day < d) {
            int watered = 0;
            for (int i = 0; i < n; i++) {
                if (h[i] < x) {
                    h[i]++;
                    watered++;
                }
            }
            if (watered != a[day]) {
                break;
            }
            day++;
            for (int i = 0; i < n; i++) {
                if (h[i] >= x) {
                    goto end;
                }
            }
        }
        end:
        printf("%d\n", day);
    }
    return 0;
}

